public class P04 {
    public static void main(String[] args) {
        int currentNumber = 0;
        int oddNumberSum = 0;

        while (currentNumber < 5) {
            currentNumber++;

            boolean isEven = currentNumber % 2 == 0;
            if (isEven) {
                continue;
            }

            oddNumberSum += currentNumber;

            if (oddNumberSum > 4) {
                break;
            }
        }

        System.out.println(currentNumber + ":" + oddNumberSum);
    }
}

